import React, { useState } from "react";

export default function YouTubeEmbed({ videoId, title }: any) {

  const [loaded, setLoaded] = useState(false);

  const thumbnail = `https://img.youtube.com/vi/${videoId}/hqdefault.jpg`;
  const embed = `https://www.youtube.com/embed/${videoId}?autoplay=1`;

  if (loaded) {
    return (
      <div style={{ position: "relative", paddingBottom: "56.25%", height: 0 }}>
        <iframe
          src={embed}
          title={title}
          style={{
            position: "absolute",
            top: 0,
            left: 0,
            width: "100%",
            height: "100%"
          }}
          frameBorder="0"
          allow="autoplay; encrypted-media"
          allowFullScreen
        />
      </div>
    );
  }

  return (
    <div
      onClick={() => setLoaded(true)}
      style={{
        position: "relative",
        paddingBottom: "56.25%",
        height: 0,
        cursor: "pointer"
      }}
    >

      <img
        src={thumbnail}
        style={{
          position: "absolute",
          width: "100%",
          height: "100%",
          objectFit: "cover"
        }}
      />

      <div
        style={{
          position: "absolute",
          top: "50%",
          left: "50%",
          transform: "translate(-50%,-50%)",
          width: 70,
          height: 50,
          background: "red",
          borderRadius: 8,
          display: "flex",
          alignItems: "center",
          justifyContent: "center"
        }}
      >
        ▶
      </div>

    </div>
  );
}