import React from "react";
import YouTubeEmbed from "./YouTubeEmbed";

export default function VideoView({ rows }: any) {

  return (
    <div>

      {rows.map((row: any) => {

        const videoId = row.video_id || row.link?.split("/embed/")[1];

        return (
          <div key={row.id} style={{ marginBottom: 40 }}>

            <h2>{row.title}</h2>

            {videoId && (
              <YouTubeEmbed
                videoId={videoId}
                title={row.title}
              />
            )}

          </div>
        );
      })}

    </div>
  );
}