import React, { useEffect, useState } from "react";
import { getSupabase } from "../../../database/supabase";

import CollectionView from "../../../components/custom/migration/CollectionView";
import ContentView from "../../../components/custom/migration/ContentView";
import EducationView from "../../../components/custom/migration/EducationView";
import GalleryView from "../../../components/custom/migration/GalleryView";
import HotNewsView from "../../../components/custom/migration/HotNewsView";
import ImageView from "../../../components/custom/migration/ImageView";
import MusicView from "../../../components/custom/migration/MusicView";
import MusicCDView from "../../../components/custom/migration/MusicCDView";
import NewsView from "../../../components/custom/migration/NewsView";
import VideoView from "../../../components/custom/migration/VideoView";

const tables = [
  "banner",
  "catecollection",
  "cateeducation",
  "category",
  "catemusic",
  "catenews",
  "collection",
  "content",
  "education",
  "gallery",
  "hotnews",
  "image",
  "music",
  "music_cd",
  "news",
  "singer",
  "video",
  "video_live",
];

const customRenderers: Record<string, any> = {
  collection: CollectionView,
  content: ContentView,
  education: EducationView,
  gallery: GalleryView,
  hotnews: HotNewsView,
  image: ImageView,
  music: MusicView,
  music_cd: MusicCDView,
  news: NewsView,
  video: VideoView,
};

export default function TablesPage() {

  const [sessionReady, setSessionReady] = useState(false);
  const [rows, setRows] = useState<any[]>([]);
  const [columns, setColumns] = useState<string[]>([]);
  const [selected, setSelected] = useState<string | null>(null);
  const [viewMode, setViewMode] = useState<"table" | "content">("table");

  const [logs, setLogs] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);

  function log(msg: string) {
    console.log(msg);
    setLogs((l) => [...l, msg]);
  }

  useEffect(() => {

    async function init() {

      log("Initializing session...");

      const supabase = await getSupabase();

      const { data } = await supabase.auth.getSession();

      if (data.session?.user) {
        log(`Logged in as ${data.session.user.email}`);
      } else {
        log("No active session");
      }

      setSessionReady(true);
    }

    init();

  }, []);

  async function loadTable(table: string) {

    if (!sessionReady) {
      log("Session not ready yet");
      return;
    }

    setSelected(table);
    setLoading(true);
    setViewMode("table");

    log(`Querying table: ${table}`);

    const supabase = await getSupabase();

    const { data, error } = await supabase
      .from(table)
      .select("*")
      .limit(100);

    if (error) {
      log(`ERROR: ${error.message}`);
      setLoading(false);
      return;
    }

    if (data) {

      log(`Loaded ${data.length} rows`);

      setRows(data);

      if (data.length > 0) {
        setColumns(Object.keys(data[0]));
      }

    }

    setLoading(false);
  }

  const Renderer = selected ? customRenderers[selected] : null;

  return (

    <div style={{ padding: 30 }}>

      <h1>Supabase Table Viewer</h1>

      <div style={{ marginBottom: 20 }}>

        <h3>Tables</h3>

        {tables.map((t) => (
          <button
            key={t}
            onClick={() => loadTable(t)}
            style={{ marginRight: 8, marginBottom: 8 }}
          >
            {t}
          </button>
        ))}

      </div>

      {Renderer && rows.length > 0 && (

        <div style={{ marginBottom: 20 }}>

          <button
            onClick={() => setViewMode("table")}
            style={{ marginRight: 10 }}
          >
            Table View
          </button>

          <button
            onClick={() => setViewMode("content")}
          >
            Content View
          </button>

        </div>

      )}

      {loading && <p>Loading table...</p>}

      {viewMode === "table" && selected && rows.length > 0 && (

        <>
          <h2>{selected}</h2>

          <table border={1} cellPadding={6}>

            <thead>
              <tr>
                {columns.map((c) => (
                  <th key={c}>{c}</th>
                ))}
              </tr>
            </thead>

            <tbody>

              {rows.map((row, i) => (
                <tr key={i}>
                  {columns.map((c) => (
                    <td key={c}>{JSON.stringify(row[c])}</td>
                  ))}
                </tr>
              ))}

            </tbody>

          </table>

        </>

      )}

      {viewMode === "content" && Renderer && (
        <Renderer rows={rows} />
      )}

      <div
        style={{
          marginTop: 40,
          padding: 10,
          border: "1px solid #ccc",
          background: "#f7f7f7",
          maxHeight: 250,
          overflow: "auto"
        }}
      >

        <h3>Debug Log</h3>

        {logs.map((l, i) => (
          <div key={i}>{l}</div>
        ))}

      </div>

    </div>

  );
}