import React from "react";

function decodeWPHTML(html: string) {
  if (!html) return "";

  try {
    return JSON.parse(`"${html.replace(/"/g, '\\"')}"`);
  } catch {
    return html
      .replace(/\\r\\n/g, "\n")
      .replace(/\\"/g, '"')
      .replace(/\\'/g, "'")
      .replace(/\\\\/g, "\\");
  }
}

export default function HTMLContent({ html }: { html: string }) {
  return (
    <div
      className="wp-html"
      dangerouslySetInnerHTML={{ __html: decodeWPHTML(html) }}
    />
  );
}