import React from "react";
import HTMLContent from "./HTMLContent";

export default function CollectionView({ rows }: any) {
  return (
    <div>
      {rows.map((row: any) => (
        <div
          key={row.id}
          style={{ border: "1px solid #ddd", padding: 20, marginBottom: 30 }}
        >
          <h2>{row.title}</h2>

          {row.image && (
            <img
              src={row.image}
              style={{ maxWidth: 400, marginBottom: 20 }}
            />
          )}

          <HTMLContent html={row.content} />
        </div>
      ))}
    </div>
  );
}